  1→<!DOCTYPE html>
  2→<html lang="en">
  3→<head>
  4→<meta charset="UTF-8">
  5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
  6→<title>Chess Demo</title>
  7→<style>
  8→  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  9→
 10→  body {
 11→    min-height: 100vh;
 12→    display: flex;
 13→    flex-direction: column;
 14→    justify-content: center;
 15→    align-items: center;
 16→    background: #1a1a2e;
 17→    font-family: system-ui, -apple-system, sans-serif;
 18→  }
 19→
 20→  .board-container {
 21→    display: inline-grid;
 22→    grid-template-columns: 2rem repeat(8, 1fr);
 23→    grid-template-rows: repeat(8, 1fr) 2rem;
 24→    max-width: min(90vw, 90vh);
 25→    aspect-ratio: 1;
 26→    width: 560px;
 27→    border: 4px solid #16213e;
 28→    border-radius: 6px;
 29→    overflow: hidden;
 30→    box-shadow: 0 8px 32px rgba(0,0,0,.5);
 31→  }
 32→
 33→  .rank-label {
 34→    display: flex;
 35→    align-items: center;
 36→    justify-content: center;
 37→    background: #16213e;
 38→    color: #a0a0b0;
 39→    font-size: 0.85rem;
 40→    font-weight: 600;
 41→    width: 2rem;
 42→  }
 43→
 44→  .file-label {
 45→    display: flex;
 46→    align-items: center;
 47→    justify-content: center;
 48→    background: #16213e;
 49→    color: #a0a0b0;
 50→    font-size: 0.85rem;
 51→    font-weight: 600;
 52→    height: 2rem;
 53→  }
 54→
 55→  .corner {
 56→    background: #16213e;
 57→  }
 58→
 59→  .square {
 60→    display: flex;
 61→    align-items: center;
 62→    justify-content: center;
 63→    font-size: clamp(1.5rem, 5vw, 3.2rem);
 64→    cursor: pointer;
 65→    user-select: none;
 66→    transition: background-color 0.15s;
 67→    aspect-ratio: 1;
 68→  }
 69→
 70→  .square.light { background: #e8dcc8; }
 71→  .square.dark  { background: #7b6b4f; }
 72→  .square:hover { filter: brightness(1.12); }
 73→
 74→  .square.selected { background: #f6e96b !important; }
 75→  .square.valid-move { position: relative; }
 76→  .square.valid-move::after {
 77→    content: '';
 78→    position: absolute;
 79→    width: 30%;
 80→    height: 30%;
 81→    background: rgba(0, 0, 0, 0.25);
 82→    border-radius: 50%;
 83→    pointer-events: none;
 84→  }
 85→  .square.valid-move.has-enemy::after {
 86→    width: 85%;
 87→    height: 85%;
 88→    background: transparent;
 89→    border: 5px solid rgba(0, 0, 0, 0.25);
 90→    border-radius: 50%;
 91→  }
 92→
 93→  .square.in-check {
 94→    background: #e74c3c !important;
 95→    box-shadow: inset 0 0 12px rgba(0,0,0,.4);
 96→  }
 97→
 98→  .turn-indicator {
 99→    text-align: center;
100→    color: #a0a0b0;
101→    font-size: 1.1rem;
102→    margin-top: 1rem;
103→    font-weight: 600;
104→  }
105→</style>
106→</head>
107→<body>
108→
109→<div class="board-container" id="board"></div>
110→<div class="turn-indicator" id="turn">White's turn</div>
111→
112→<script>
113→const PIECES = {
114→  K: { type: 'king',   color: 'white', symbol: '\u2654' },
115→  Q: { type: 'queen',  color: 'white', symbol: '\u2655' },
116→  R: { type: 'rook',   color: 'white', symbol: '\u2656' },
117→  B: { type: 'bishop', color: 'white', symbol: '\u2657' },
118→  N: { type: 'knight', color: 'white', symbol: '\u2658' },
119→  P: { type: 'pawn',   color: 'white', symbol: '\u2659' },
120→  k: { type: 'king',   color: 'black', symbol: '\u265A' },
121→  q: { type: 'queen',  color: 'black', symbol: '\u265B' },
122→  r: { type: 'rook',   color: 'black', symbol: '\u265C' },
123→  b: { type: 'bishop', color: 'black', symbol: '\u265D' },
124→  n: { type: 'knight', color: 'black', symbol: '\u265E' },
125→  p: { type: 'pawn',   color: 'black', symbol: '\u265F' },
126→};
127→
128→function makePiece(key) {
129→  if (!key) return null;
130→  const p = PIECES[key];
131→  return { type: p.type, color: p.color, symbol: p.symbol };
132→}
133→
134→// Board state: board[row][col], row 0 = rank 8 (top)
135→const INITIAL = [
136→  ['r','n','b','q','k','b','n','r'],
137→  ['p','p','p','p','p','p','p','p'],
138→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
139→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
140→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
141→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
142→  ['P','P','P','P','P','P','P','P'],
143→  ['R','N','B','Q','K','B','N','R'],
144→];
145→
146→const boardState = INITIAL.map(row => row.map(makePiece));
147→
148→const FILES = ['a','b','c','d','e','f','g','h'];
149→const container = document.getElementById('board');
150→const turnIndicator = document.getElementById('turn');
151→
152→let currentTurn = 'white';
153→let selectedSquare = null; // { row, col }
154→let validMoves = [];       // [{ row, col }, ...]
155→let gameOver = false;
156→
157→function inBounds(r, c) {
158→  return r >= 0 && r < 8 && c >= 0 && c < 8;
159→}
160→
161→function slidingMoves(row, col, directions) {
162→  const piece = boardState[row][col];
163→  const moves = [];
164→  for (const [dr, dc] of directions) {
165→    let r = row + dr, c = col + dc;
166→    while (inBounds(r, c)) {
167→      const target = boardState[r][c];
168→      if (!target) {
169→        moves.push({ row: r, col: c });
170→      } else {
171→        if (target.color !== piece.color) moves.push({ row: r, col: c });
172→        break;
173→      }
174→      r += dr;
175→      c += dc;
176→    }
177→  }
178→  return moves;
179→}
180→
181→function getValidMoves(piece, row, col) {
182→  const moves = [];
183→
184→  if (piece.type === 'pawn') {
185→    const dir = piece.color === 'white' ? -1 : 1;
186→    const startRow = piece.color === 'white' ? 6 : 1;
187→    // Forward one
188→    if (inBounds(row + dir, col) && !boardState[row + dir][col]) {
189→      moves.push({ row: row + dir, col });
190→      // Forward two from start
191→      if (row === startRow && !boardState[row + 2 * dir][col]) {
192→        moves.push({ row: row + 2 * dir, col });
193→      }
194→    }
195→    // Diagonal captures
196→    for (const dc of [-1, 1]) {
197→      const nr = row + dir, nc = col + dc;
198→      if (inBounds(nr, nc) && boardState[nr][nc] && boardState[nr][nc].color !== piece.color) {
199→        moves.push({ row: nr, col: nc });
200→      }
201→    }
202→  }
203→
204→  if (piece.type === 'rook' || piece.type === 'queen') {
205→    moves.push(...slidingMoves(row, col, [[1,0],[-1,0],[0,1],[0,-1]]));
206→  }
207→
208→  if (piece.type === 'bishop' || piece.type === 'queen') {
209→    moves.push(...slidingMoves(row, col, [[1,1],[1,-1],[-1,1],[-1,-1]]));
210→  }
211→
212→  if (piece.type === 'knight') {
213→    for (const [dr, dc] of [[2,1],[2,-1],[-2,1],[-2,-1],[1,2],[1,-2],[-1,2],[-1,-2]]) {
214→      const nr = row + dr, nc = col + dc;
215→      if (inBounds(nr, nc)) {
216→        const target = boardState[nr][nc];
217→        if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
218→      }
219→    }
220→  }
221→
222→  if (piece.type === 'king') {
223→    for (let dr = -1; dr <= 1; dr++) {
224→      for (let dc = -1; dc <= 1; dc++) {
225→        if (dr === 0 && dc === 0) continue;
226→        const nr = row + dr, nc = col + dc;
227→        if (inBounds(nr, nc)) {
228→          const target = boardState[nr][nc];
229→          if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
230→        }
231→      }
232→    }
233→  }
234→
235→  return moves;
236→}
237→
238→function findKing(color) {
239→  for (let r = 0; r < 8; r++) {
240→    for (let c = 0; c < 8; c++) {
241→      const p = boardState[r][c];
242→      if (p && p.type === 'king' && p.color === color) return { row: r, col: c };
243→    }
244→  }
245→  return null;
246→}
247→
248→function isKingInCheck(color, board) {
249→  // Find king position on the given board
250→  let kingRow = -1, kingCol = -1;
251→  for (let r = 0; r < 8; r++) {
252→    for (let c = 0; c < 8; c++) {
253→      const p = board[r][c];
254→      if (p && p.type === 'king' && p.color === color) {
255→        kingRow = r; kingCol = c; break;
256→      }
257→    }
258→    if (kingRow >= 0) break;
259→  }
260→
261→  const enemy = color === 'white' ? 'black' : 'white';
262→
263→  // Check all enemy pieces for attacks on king square
264→  for (let r = 0; r < 8; r++) {
265→    for (let c = 0; c < 8; c++) {
266→      const p = board[r][c];
267→      if (!p || p.color !== enemy) continue;
268→
269→      if (p.type === 'pawn') {
270→        const dir = p.color === 'white' ? -1 : 1;
271→        if (r + dir === kingRow && (c - 1 === kingCol || c + 1 === kingCol)) return true;
272→      } else if (p.type === 'knight') {
273→        for (const [dr, dc] of [[2,1],[2,-1],[-2,1],[-2,-1],[1,2],[1,-2],[-1,2],[-1,-2]]) {
274→          if (r + dr === kingRow && c + dc === kingCol) return true;
275→        }
276→      } else if (p.type === 'king') {
277→        if (Math.abs(r - kingRow) <= 1 && Math.abs(c - kingCol) <= 1) return true;
278→      } else {
279→        // Sliding pieces
280→        let dirs = [];
281→        if (p.type === 'rook' || p.type === 'queen') dirs.push([1,0],[-1,0],[0,1],[0,-1]);
282→        if (p.type === 'bishop' || p.type === 'queen') dirs.push([1,1],[1,-1],[-1,1],[-1,-1]);
283→        for (const [dr, dc] of dirs) {
284→          let sr = r + dr, sc = c + dc;
285→          while (sr >= 0 && sr < 8 && sc >= 0 && sc < 8) {
286→            if (sr === kingRow && sc === kingCol) return true;
287→            if (board[sr][sc]) break;
288→            sr += dr; sc += dc;
289→          }
290→        }
291→      }
292→    }
293→  }
294→  return false;
295→}
296→
297→function getLegalMoves(piece, row, col) {
298→  const pseudo = getValidMoves(piece, row, col);
299→  return pseudo.filter(m => {
300→    // Simulate the move on a shallow copy
301→    const saved = boardState[m.row][m.col];
302→    boardState[m.row][m.col] = boardState[row][col];
303→    boardState[row][col] = null;
304→    const inCheck = isKingInCheck(piece.color, boardState);
305→    // Undo
306→    boardState[row][col] = boardState[m.row][m.col];
307→    boardState[m.row][m.col] = saved;
308→    return !inCheck;
309→  });
310→}
311→
312→function hasAnyLegalMoves(color) {
313→  for (let r = 0; r < 8; r++) {
314→    for (let c = 0; c < 8; c++) {
315→      const p = boardState[r][c];
316→      if (p && p.color === color && getLegalMoves(p, r, c).length > 0) return true;
317→    }
318→  }
319→  return false;
320→}
321→
322→function highlightCheck() {
323→  // Remove previous check highlights
324→  container.querySelectorAll('.square.in-check').forEach(sq => sq.classList.remove('in-check'));
325→  for (const color of ['white', 'black']) {
326→    if (isKingInCheck(color, boardState)) {
327→      const king = findKing(color);
328→      if (king) getSquareEl(king.row, king.col).classList.add('in-check');
329→    }
330→  }
331→}
332→
333→function checkGameState() {
334→  const inCheck = isKingInCheck(currentTurn, boardState);
335→  const hasLegal = hasAnyLegalMoves(currentTurn);
336→
337→  highlightCheck();
338→
339→  if (!hasLegal) {
340→    gameOver = true;
341→    if (inCheck) {
342→      const winner = currentTurn === 'white' ? 'Black' : 'White';
343→      turnIndicator.textContent = `Checkmate! ${winner} wins!`;
344→    } else {
345→      turnIndicator.textContent = 'Stalemate — draw!';
346→    }
347→  } else if (inCheck) {
348→    const name = currentTurn === 'white' ? 'White' : 'Black';
349→    turnIndicator.textContent = `${name}'s turn — Check!`;
350→  }
351→}
352→
353→function getSquareEl(row, col) {
354→  return container.querySelector(`.square[data-row="${row}"][data-col="${col}"]`);
355→}
356→
357→function clearHighlights() {
358→  container.querySelectorAll('.square.selected, .square.valid-move').forEach(sq => {
359→    sq.classList.remove('selected', 'valid-move', 'has-enemy');
360→  });
361→}
362→
363→function applyHighlights() {
364→  if (!selectedSquare) return;
365→  getSquareEl(selectedSquare.row, selectedSquare.col).classList.add('selected');
366→  for (const m of validMoves) {
367→    const el = getSquareEl(m.row, m.col);
368→    el.classList.add('valid-move');
369→    if (boardState[m.row][m.col]) el.classList.add('has-enemy');
370→  }
371→}
372→
373→function movePiece(fromRow, fromCol, toRow, toCol) {
374→  boardState[toRow][toCol] = boardState[fromRow][fromCol];
375→  boardState[fromRow][fromCol] = null;
376→
377→  // Update DOM
378→  const fromEl = getSquareEl(fromRow, fromCol);
379→  const toEl = getSquareEl(toRow, toCol);
380→  fromEl.textContent = '';
381→  toEl.textContent = boardState[toRow][toCol].symbol;
382→
383→  // Switch turn
384→  currentTurn = currentTurn === 'white' ? 'black' : 'white';
385→  turnIndicator.textContent = currentTurn === 'white' ? "White's turn" : "Black's turn";
386→
387→  checkGameState();
388→}
389→
390→function handleClick(row, col) {
391→  if (gameOver) return;
392→  const piece = boardState[row][col];
393→
394→  // If a piece is already selected
395→  if (selectedSquare) {
396→    // Check if clicking a valid move destination
397→    const isValid = validMoves.some(m => m.row === row && m.col === col);
398→    if (isValid) {
399→      clearHighlights();
400→      movePiece(selectedSquare.row, selectedSquare.col, row, col);
401→      selectedSquare = null;
402→      validMoves = [];
403→      return;
404→    }
405→
406→    // Deselect current piece
407→    const prevRow = selectedSquare.row;
408→    const prevCol = selectedSquare.col;
409→    clearHighlights();
410→    selectedSquare = null;
411→    validMoves = [];
412→
413→    // If clicked a different own piece, select it instead
414→    if (piece && piece.color === currentTurn && !(row === prevRow && col === prevCol)) {
415→      // fall through to selection below
416→    } else {
417→      return;
418→    }
419→  }
420→
421→  // Select a piece of the current player
422→  if (piece && piece.color === currentTurn) {
423→    selectedSquare = { row, col };
424→    validMoves = getLegalMoves(piece, row, col);
425→    applyHighlights();
426→  }
427→}
428→
429→// Build the board
430→for (let row = 0; row < 8; row++) {
431→  const rl = document.createElement('div');
432→  rl.className = 'rank-label';
433→  rl.textContent = 8 - row;
434→  container.appendChild(rl);
435→
436→  for (let col = 0; col < 8; col++) {
437→    const sq = document.createElement('div');
438→    const isLight = (row + col) % 2 === 0;
439→    sq.className = 'square ' + (isLight ? 'light' : 'dark');
440→    sq.dataset.row = row;
441→    sq.dataset.col = col;
442→
443→    const piece = boardState[row][col];
444→    if (piece) sq.textContent = piece.symbol;
445→
446→    sq.addEventListener('click', () => handleClick(row, col));
447→
448→    container.appendChild(sq);
449→  }
450→}
451→
452→// File labels row
453→const corner = document.createElement('div');
454→corner.className = 'corner';
455→container.appendChild(corner);
456→
457→for (const f of FILES) {
458→  const fl = document.createElement('div');
459→  fl.className = 'file-label';
460→  fl.textContent = f;
461→  container.appendChild(fl);
462→}
463→</script>
464→</body>
465→</html>
